async function getClusterOverview() {
  const [{ Payload }, { Items: dashItems = [] }] = await Promise.all([
    lambda.send(new InvokeCommand({
      FunctionName: MCP_API_FUNCTION_NAME,
      InvocationType: "RequestResponse",
      Payload: JSON.stringify({ httpMethod: "GET", path: "/api/cluster" }),
    })),
    ddb.send(new ScanCommand({
      TableName: DASHBOARD_TABLE,
      FilterExpression: "begins_with(pk, :prefix) AND sk = :meta",
      ExpressionAttributeValues: { ":prefix": { S: "SITE#" }, ":meta": { S: "METADATA" } },
      ProjectionExpression: "pk, container_schedule",
    })),
  ]);

  const scheduleMap = {};
  for (const item of dashItems) {
    const name = item.pk.S.replace("SITE#", "");
    scheduleMap[name] = item.container_schedule?.S || "weekday-business";
  }

  const data = JSON.parse(JSON.parse(new TextDecoder().decode(Payload)).body);
  for (const svc of data.services || []) {
    svc.container_schedule = scheduleMap[svc.site_name] || "weekday-business";
  }
  return data;
}

