async function updateContainerSchedule(siteName, { schedule }, callerEmail) {
  const validSchedules = ["weekday-business", "weekday-24x7", "24x7"];
  if (!schedule || !validSchedules.includes(schedule)) {
    throw Object.assign(new Error(`schedule must be one of: ${validSchedules.join(", ")}`), { statusCode: 400 });
  }

  const site = await getSite(siteName);
  if (!(site.site_type || "").includes("container")) {
    throw Object.assign(new Error("Site does not have container component"), { statusCode: 400 });
  }

  const now = new Date().toISOString();
  await ddb.send(new UpdateItemCommand({
    TableName: DASHBOARD_TABLE,
    Key: { pk: { S: `SITE#${siteName}` }, sk: { S: "METADATA" } },
    UpdateExpression: "SET container_schedule = :sched, updated_at = :now",
    ExpressionAttributeValues: {
      ":sched": { S: schedule },
      ":now": { S: now },
    },
  }));

  return { site_name: siteName, schedule };
}

