async function updateContainerSchedule(siteName, { schedule }, callerEmail) {
  const validSchedules = ["weekday-business", "weekday-24x7", "24x7"];
  if (!schedule || !validSchedules.includes(schedule)) {
    throw Object.assign(new Error(`schedule must be one of: ${validSchedules.join(", ")}`), { statusCode: 400 });
  }

  const site = await getSite(siteName);
  if (!(site.site_type || "").includes("container")) {
    throw Object.assign(new Error("Site does not have container component"), { statusCode: 400 });
  }

  const now = new Date().toISOString();
  await ddb.send(new UpdateItemCommand({
    TableName: DASHBOARD_TABLE,
    Key: { pk: { S: `SITE#${siteName}` }, sk: { S: "METADATA" } },
    UpdateExpression: "SET container_schedule = :sched, updated_at = :now",
    ExpressionAttributeValues: {
      ":sched": { S: schedule },
      ":now": { S: now },
    },
  }));

  const currentStatus = site.container_status;
  if (currentStatus === "deployed" || currentStatus === "stopped") {
    const wantRunning = shouldBeRunning(schedule);
    const isRunning = currentStatus === "deployed";

    if (wantRunning && !isRunning) {
      await startContainer(siteName, callerEmail);
    } else if (!wantRunning && isRunning) {
      await stopContainer(siteName, callerEmail);
    }
  }

  return { site_name: siteName, schedule };
}

function shouldBeRunning(schedule) {
  const rules = {
    "weekday-business": { days: [1, 2, 3, 4, 5], startHour: 8, endHour: 18 },
    "weekday-24x7":     { days: [1, 2, 3, 4, 5], startHour: 0, endHour: 24 },
    "24x7":             { days: [0, 1, 2, 3, 4, 5, 6], startHour: 0, endHour: 24 },
  };
  const rule = rules[schedule];
  if (!rule) return true;
  const now = new Date(new Date().toLocaleString("en-US", { timeZone: "Europe/London" }));
  const timeDecimal = now.getHours() + now.getMinutes() / 60;
  return rule.days.includes(now.getDay()) && timeDecimal >= rule.startHour && timeDecimal < rule.endHour;
}

